function arrAdd<T>(list: T[], value: T): T[] {
  const clone = list.slice();
  const index = clone.indexOf(value);
  if (index === -1) {
    clone.push(value);
  }
  return clone;
}

function arrDel<T>(list: T[], value: T): T[] {
  const clone = list.slice();
  const index = clone.indexOf(value);
  if (index !== -1) {
    clone.splice(index, 1);
  }
  return clone;
}

