import type { GetRowKey, Key } from '../../interface';

// recursion (flat tree structure)
function fillRecords<T>(
  list: FlattenData<T>[],
  record: T,
  indent: number,
  childrenColumnName: string,
  expandedKeys: Set<Key>,
  getRowKey: GetRowKey<T>,
  index: number,
) {
  const key = getRowKey(record, index);

  list.push({
    record,
    indent,
    index,
    rowKey: key,
  });

  const expanded = expandedKeys?.has(key);

  const children = record
    ? (record as Record<PropertyKey, unknown>)[childrenColumnName]
    : undefined;

  if (Array.isArray(children) && expanded) {
    // expanded state, flat record
    for (let i = 0; i < children.length; i += 1) {
      fillRecords(
        list,
        children[i] as T,
        indent + 1,
        childrenColumnName,
        expandedKeys,
        getRowKey,
        i,
      );
    }
  }
}

export interface FlattenData<RecordType> {
  record: RecordType;
  indent: number;
  index: number;
  rowKey: Key;
}

/**
 * flat tree data on expanded state
 *
 * @export
 * @template T
 * @param {*} data : table data
 * @param {string} childrenColumnName : \u6307\u5B9A\u6811\u5F62\u7ED3\u6784\u7684\u5217\u540D
 * @param {Set<Key>} expandedKeys : \u5C55\u5F00\u7684\u884C\u5BF9\u5E94\u7684keys
 * @param {GetRowKey<T>} getRowKey  : \u83B7\u53D6\u5F53\u524DrowKey\u7684\u65B9\u6CD5
 * @returns flattened data
 */
export default function useFlattenRecords<T>(
  data: T[] | readonly T[],
  childrenColumnName: string,
  expandedKeys: Set<Key>,
  getRowKey: GetRowKey<T>,
): FlattenData<T>[] {
  const arr = React.useMemo<FlattenData<T>[]>(() => {
    if (expandedKeys?.size) {
      const list: FlattenData<T>[] = [];

      // collect flattened record
      for (let i = 0; i < data?.length; i += 1) {
        const record = data[i];

        // using array.push or spread operator may cause "Maximum call stack size exceeded" exception if array size is big enough.
        fillRecords(list, record, 0, childrenColumnName, expandedKeys, getRowKey, i);
      }

      return list;
    }

    return data?.map((item, index) => {
      return {
        record: item,
        indent: 0,
        index,
        rowKey: getRowKey(item, index),
      };
    });
  }, [data, childrenColumnName, expandedKeys, getRowKey]);

  return arr;
}
